            {
                EnrollmentID = 2,
                CourseID = 4022,
                StudentID = 11,
                Grade = Grade.B
            };

            context.Enrollments.AddRange(enrollment1, enrollment2);
            context.SaveChanges();

            var ca = new CourseAssignment
            {
                CourseID = 1050,
                InstructorID = 1
            };

            context.CourseAssignments.Add(ca);
            context.SaveChanges();

            var office = new OfficeAssignment
            {
                InstructorID = 2,
                Location = "Smith 17"
            };

            context.OfficeAssignments.Add(office);
            context.SaveChanges();
        }

        public static void SetupControllerContext(Controller controller)
        {
            var httpContext = new DefaultHttpContext();
            var tempData = new TempDataDictionary(httpContext, Mock.Of<ITempDataProvider>());
            controller.TempData = tempData;
            controller.ControllerContext = new ControllerContext
            {
                HttpContext = httpContext
            };
        }
    }
}

