using ContosoUniversity.Models;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class PersonTests
    {
        private class ConcretePerson : Person { }

        [Fact]
        public void FullName_ReturnsLastNameCommaFirstName()
        {
            var person = new ConcretePerson
            {
                FirstMidName = "John",
                LastName = "Doe"
            };

            Assert.Equal("Doe, John", person.FullName);
        }

        [Fact]
        public void FullName_WithEmptyFirstName_ReturnsLastNameComma()
        {
            var person = new ConcretePerson
            {
                FirstMidName = "",
                LastName = "Doe"
            };

            Assert.Equal("Doe, ", person.FullName);
        }

        [Fact]
        public void ID_CanBeSetAndRetrieved()
        {
            var person = new ConcretePerson { ID = 42 };
            Assert.Equal(42, person.ID);
        }

        [Fact]
        public void LastName_CanBeSetAndRetrieved()
        {
            var person = new ConcretePerson { LastName = "Smith" };
            Assert.Equal("Smith", person.LastName);
        }

        [Fact]
        public void FirstMidName_CanBeSetAndRetrieved()
        {
            var person = new ConcretePerson { FirstMidName = "Jane" };
            Assert.Equal("Jane", person.FirstMidName);
        }
    }
}

using ContosoUniversity.Models;
