using ContosoUniversity.Models;
using System;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class NotificationTests
    {
        [Fact]
        public void Id_CanBeSetAndRetrieved()
        {
            var notification = new Notification { Id = 42 };
            Assert.Equal(42, notification.Id);
        }

        [Fact]
        public void EntityType_CanBeSetAndRetrieved()
        {
            var notification = new Notification { EntityType = "Student" };
            Assert.Equal("Student", notification.EntityType);
        }

        [Fact]
        public void EntityId_CanBeSetAndRetrieved()
        {
            var notification = new Notification { EntityId = "123" };
            Assert.Equal("123", notification.EntityId);
        }

        [Fact]
        public void Operation_CanBeSetAndRetrieved()
        {
            var notification = new Notification { Operation = "CREATE" };
            Assert.Equal("CREATE", notification.Operation);
        }

        [Fact]
        public void Message_CanBeSetAndRetrieved()
        {
            var notification = new Notification { Message = "Test message" };
            Assert.Equal("Test message", notification.Message);
        }

        [Fact]
        public void CreatedAt_CanBeSetAndRetrieved()
        {
            var now = DateTime.Now;
            var notification = new Notification { CreatedAt = now };
            Assert.Equal(now, notification.CreatedAt);
        }

        [Fact]
        public void CreatedBy_CanBeSetAndRetrieved()
        {
            var notification = new Notification { CreatedBy = "admin" };
            Assert.Equal("admin", notification.CreatedBy);
        }

        [Fact]
        public void IsRead_DefaultsToFalse()
        {
            var notification = new Notification();
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void IsRead_CanBeSetToTrue()
        {
            var notification = new Notification { IsRead = true };
            Assert.True(notification.IsRead);
        }

        [Fact]
        public void ReadAt_CanBeNull()
        {
            var notification = new Notification();
            Assert.Null(notification.ReadAt);
        }

        [Fact]
        public void ReadAt_CanBeSetAndRetrieved()
        {
            var now = DateTime.Now;
            var notification = new Notification { ReadAt = now };
            Assert.Equal(now, notification.ReadAt);
        }

        [Theory]
        [InlineData(EntityOperation.CREATE)]
        [InlineData(EntityOperation.UPDATE)]
        [InlineData(EntityOperation.DELETE)]
        public void EntityOperation_AllValuesExist(EntityOperation op)
        {
            Assert.True(Enum.IsDefined(typeof(EntityOperation), op));
        }
    }
}

