using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestHelpers.CreateSeededContext();
            _controller = new StudentsController(_context);
            TestHelpers.SetupControllerContext(_controller);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        // --- Index Tests ---

        [Fact]
        public void Index_ReturnsViewResult_WithPaginatedStudents()
        {
            var result = _controller.Index(null, null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal(3, model.Count); // 3 seeded students
        }

        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            var result = _controller.Index(null, null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal("Alexander", model[0].LastName);
            Assert.Equal("Alonso", model[1].LastName);
            Assert.Equal("Anand", model[2].LastName);
        }

        [Fact]
        public void Index_NameDescSort_OrdersByLastNameDescending()
        {
            var result = _controller.Index("name_desc", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal("Anand", model[0].LastName);
            Assert.Equal("Alonso", model[1].LastName);
            Assert.Equal("Alexander", model[2].LastName);
        }

        [Fact]
        public void Index_DateSort_OrdersByEnrollmentDateAscending()
        {
            var result = _controller.Index("Date", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal("Alexander", model[0].LastName); // 2010
            Assert.Equal("Alonso", model[1].LastName); // 2012
        }

        [Fact]
        public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
        {
            var result = _controller.Index("date_desc", null, null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal("Anand", model[0].LastName); // 2013
        }

        [Fact]
        public void Index_SearchString_FiltersStudents()
        {
            var result = _controller.Index(null, null, "Alexander", null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Single(model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_SearchString_FiltersByFirstName()
        {
            var result = _controller.Index(null, null, "Carson", null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Single(model);
            Assert.Equal("Carson", model[0].FirstMidName);
        }

        [Fact]
        public void Index_SearchString_ResetsPage()
        {
            var result = _controller.Index(null, null, "Alex", 3);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_NoSearchString_UsesCurrentFilter()
        {
            var result = _controller.Index(null, "Alonso", null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_SetsViewBagSortParameters()
        {
            _controller.Index(null, null, null, null);

            Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);
            Assert.Equal("Date", _controller.ViewBag.DateSortParm);
        }

        [Fact]
        public void Index_WithNameDescSort_SetsViewBagSortParameters()
        {
            _controller.Index("name_desc", null, null, null);

            Assert.Equal("", _controller.ViewBag.NameSortParm);
        }

        [Fact]
        public void Index_WithDateSort_SetsDateDescSortParm()
        {
            _controller.Index("Date", null, null, null);

            Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
        }

        // --- Details Tests ---

        [Fact]
        public void Details_ReturnsNotFound_WhenIdIsNull()
        {
            var result = _controller.Details(null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Details_ReturnsView_WithStudent()
        {
            var studentId = _context.Students.First().ID;
            var result = _controller.Details(studentId);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal(studentId, model.ID);
        }

        // --- Create GET Tests ---

        [Fact]
        public void Create_GET_ReturnsViewResult_WithDefaultDate()
        {
            var result = _controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal(DateTime.Today, model.EnrollmentDate);
        }

        // --- Create POST Tests ---

        [Fact]
        public void Create_POST_RedirectsToIndex_WhenModelIsValid()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2023-09-01")
            };

            var result = _controller.Create(student);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Create_POST_AddsStudentToDatabase()
        {
            var student = new Student
            {
                FirstMidName = "New",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2023-09-01")
            };

            _controller.Create(student);

            Assert.Equal(4, _context.Students.Count());
        }

        [Fact]
        public void Create_POST_ReturnsView_WhenModelStateInvalid()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Parse("2023-09-01")
            };

            var result = _controller.Create(student);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.IsType<Student>(viewResult.Model);
        }

        [Fact]
        public void Create_POST_ReturnsView_WhenEnrollmentDateIsMinValue()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_POST_ReturnsView_WhenEnrollmentDateOutOfRange()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new DateTime(1752, 1, 1)
            };

            var result = _controller.Create(student);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        // --- Edit GET Tests ---

        [Fact]
        public void Edit_GET_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Edit((int?)null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Edit_GET_ReturnsNotFound_WhenStudentDoesNotExist()
        {
            var result = _controller.Edit(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_GET_ReturnsView_WithStudent()
        {
            var studentId = _context.Students.First().ID;
            var result = _controller.Edit(studentId);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal(studentId, model.ID);
        }

        // --- Edit POST Tests ---

        [Fact]
        public void Edit_POST_RedirectsToIndex_WhenModelIsValid()
        {
            var existing = _context.Students.First();
            _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var student = new Student
            {
                ID = existing.ID,
                FirstMidName = "Updated",
                LastName = "Name",
                EnrollmentDate = DateTime.Parse("2023-09-01")
            };

            var result = _controller.Edit(student);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Edit_POST_ReturnsView_WhenModelStateInvalid()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                ID = 10,
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Parse("2023-09-01")
            };

            var result = _controller.Edit(student);

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Edit_POST_ReturnsView_WhenEnrollmentDateIsDefault()
        {
            var student = new Student
            {
                ID = 10,
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = default
            };

            var result = _controller.Edit(student);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        // --- Delete GET Tests ---

        [Fact]
        public void Delete_GET_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Delete(null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Delete_GET_ReturnsNotFound_WhenStudentDoesNotExist()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_GET_ReturnsView_WithStudent()
        {
            var studentId = _context.Students.First().ID;
            var result = _controller.Delete(studentId);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Student>(viewResult.Model);
            Assert.Equal(studentId, model.ID);
        }

        // --- DeleteConfirmed Tests ---

        [Fact]
        public void DeleteConfirmed_RemovesStudent_AndRedirectsToIndex()
        {
            var studentId = _context.Students.First().ID;
            var initialCount = _context.Students.Count();

            var result = _controller.DeleteConfirmed(studentId);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.Equal(initialCount - 1, _context.Students.Count());
        }

        [Fact]
        public void DeleteConfirmed_RedirectsToIndex_OnError()
        {
            // Trying to delete a non-existent student should catch the exception
            var result = _controller.DeleteConfirmed(999);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        // --- Search edge cases ---

        [Fact]
        public void Index_EmptySearchString_ReturnsAllStudents()
        {
            var result = _controller.Index(null, null, "", null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void Index_NonMatchingSearch_ReturnsEmpty()
        {
            var result = _controller.Index(null, null, "ZZZZZ", null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
            Assert.Empty(model);
        }
    }
}

using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
