using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestHelpers.CreateSeededContext();
            _controller = new InstructorsController(_context);
            TestHelpers.SetupControllerContext(_controller);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        // --- Index ---

        [Fact]
        public void Index_ReturnsViewResult_WithInstructorIndexData()
        {
            var result = _controller.Index(null, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.NotNull(model.Instructors);
            Assert.Equal(2, model.Instructors.Count());
        }

        [Fact]
        public void Index_WithInstructorId_ShowsCourses()
        {
            var instructorId = _context.Instructors.First().ID;
            var result = _controller.Index(instructorId, null);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.NotNull(model.Courses);
        }

        [Fact]
        public void Index_WithInstructorIdAndCourseId_ShowsEnrollments()
        {
            var instructor = _context.Instructors.First();
            var courseAssignment = _context.CourseAssignments
                .Where(ca => ca.InstructorID == instructor.ID)
                .First();

            var result = _controller.Index(instructor.ID, courseAssignment.CourseID);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
            Assert.NotNull(model.Enrollments);
        }

        // --- Details ---

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Details(null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Details_ReturnsNotFound_WhenInstructorDoesNotExist()
        {
            var result = _controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ReturnsView_WithInstructor()
        {
            var instructorId = _context.Instructors.First().ID;
            var result = _controller.Details(instructorId);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.Equal(instructorId, model.ID);
        }

        // --- Create GET ---

        [Fact]
        public void Create_GET_ReturnsView_WithAssignedCourseData()
        {
            var result = _controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.NotNull(model.CourseAssignments);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        // --- Create POST ---

        [Fact]
        public void Create_POST_RedirectsToIndex_WhenValid()
        {
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2020-01-01")
            };

            var result = _controller.Create(instructor, null);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Create_POST_AddsInstructorToDatabase()
        {
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2020-01-01")
            };

            _controller.Create(instructor, null);

            Assert.Equal(3, _context.Instructors.Count());
        }

        [Fact]
        public void Create_POST_WithSelectedCourses_AddsCourseAssignments()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Course",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2020-01-01")
            };

            var selectedCourses = new[] { "1050", "4022" };

            var result = _controller.Create(instructor, selectedCourses);

            Assert.IsType<RedirectToActionResult>(result);
            var saved = _context.Instructors.Where(i => i.LastName == "Instructor").First();
            var assignments = _context.CourseAssignments.Where(ca => ca.InstructorID == saved.ID).ToList();
            Assert.Equal(2, assignments.Count);
        }

        [Fact]
        public void Create_POST_ReturnsView_WhenModelStateInvalid()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                HireDate = DateTime.Parse("2020-01-01")
            };

            var result = _controller.Create(instructor, null);

            Assert.IsType<ViewResult>(result);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        // --- Edit GET ---

        [Fact]
        public void Edit_GET_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Edit((int?)null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Edit_GET_ReturnsView_WithInstructor()
        {
            var instructorId = _context.Instructors.First().ID;
            var result = _controller.Edit(instructorId);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.Equal(instructorId, model.ID);
            Assert.NotNull(_controller.ViewBag.Courses);
        }

        // --- Delete GET ---

        [Fact]
        public void Delete_GET_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Delete(null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Delete_GET_ReturnsNotFound_WhenInstructorDoesNotExist()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_GET_ReturnsView_WithInstructor()
        {
            var instructorId = _context.Instructors.First().ID;
            var result = _controller.Delete(instructorId);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Instructor>(viewResult.Model);
            Assert.Equal(instructorId, model.ID);
        }

        // --- DeleteConfirmed ---

        [Fact]
        public void DeleteConfirmed_RemovesInstructor_AndRedirectsToIndex()
        {
            // Use an instructor that is NOT the department administrator to avoid FK issues
            // Add a fresh instructor with no department ties
            var instructor = new Instructor
            {
                FirstMidName = "Temp",
                LastName = "Delete",
                HireDate = DateTime.Parse("2020-01-01")
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var initialCount = _context.Instructors.Count();

            var result = _controller.DeleteConfirmed(instructor.ID);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.Equal(initialCount - 1, _context.Instructors.Count());
        }

        [Fact]
        public void DeleteConfirmed_NullsDepartmentAdministrator_WhenInstructorIsAdmin()
        {
            var dept = _context.Departments.First();
            var adminId = dept.InstructorID.Value;

            _controller.DeleteConfirmed(adminId);

            var updatedDept = _context.Departments.Find(dept.DepartmentID);
            Assert.Null(updatedDept.InstructorID);
        }
    }
}

