using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly DepartmentsController _controller;

        public DepartmentsControllerTests()
        {
            _context = TestHelpers.CreateSeededContext();
            _controller = new DepartmentsController(_context);
            TestHelpers.SetupControllerContext(_controller);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        // --- Index ---

        [Fact]
        public void Index_ReturnsViewResult_WithDepartments()
        {
            var result = _controller.Index();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<List<Department>>(viewResult.Model);
            Assert.Equal(2, model.Count);
        }

        // --- Details ---

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Details(null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Details_ReturnsNotFound_WhenDepartmentDoesNotExist()
        {
            var result = _controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ReturnsView_WithDepartment()
        {
            var deptId = _context.Departments.First().DepartmentID;
            var result = _controller.Details(deptId);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Department>(viewResult.Model);
            Assert.Equal(deptId, model.DepartmentID);
        }

        // --- Create GET ---

        [Fact]
        public void Create_GET_ReturnsView_WithInstructorSelectList()
        {
            var result = _controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        // --- Create POST ---

        [Fact]
        public void Create_POST_RedirectsToIndex_WhenValid()
        {
            var dept = new Department
            {
                Name = "Science",
                Budget = 200000,
                StartDate = DateTime.Parse("2020-09-01"),
                InstructorID = 1
            };

            var result = _controller.Create(dept);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Create_POST_AddsDepartmentToDatabase()
        {
            var dept = new Department
            {
                Name = "Science",
                Budget = 200000,
                StartDate = DateTime.Parse("2020-09-01"),
                InstructorID = 1
            };

            _controller.Create(dept);

            Assert.Equal(3, _context.Departments.Count());
        }

        [Fact]
        public void Create_POST_ReturnsView_WhenModelStateInvalid()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var dept = new Department
            {
                Budget = 200000,
                StartDate = DateTime.Parse("2020-09-01")
            };

            var result = _controller.Create(dept);

            Assert.IsType<ViewResult>(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        // --- Edit GET ---

        [Fact]
        public void Edit_GET_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Edit((int?)null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Edit_GET_ReturnsNotFound_WhenDepartmentDoesNotExist()
        {
            var result = _controller.Edit(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_GET_ReturnsView_WithDepartment()
        {
            var deptId = _context.Departments.First().DepartmentID;
            var result = _controller.Edit(deptId);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Department>(viewResult.Model);
            Assert.Equal(deptId, model.DepartmentID);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        // --- Edit POST ---

        [Fact]
        public void Edit_POST_RedirectsToIndex_WhenValid()
        {
            var existing = _context.Departments.First();
            _context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var dept = new Department
            {
                DepartmentID = existing.DepartmentID,
                Name = "Updated English",
                Budget = 400000,
                StartDate = DateTime.Parse("2020-09-01"),
                InstructorID = 1
            };

            var result = _controller.Edit(dept);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
        }

        [Fact]
        public void Edit_POST_ReturnsView_WhenModelStateInvalid()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var dept = new Department
            {
                DepartmentID = 1,
                Budget = 400000,
                StartDate = DateTime.Parse("2020-09-01")
            };

            var result = _controller.Edit(dept);

            Assert.IsType<ViewResult>(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        // --- Delete GET ---

        [Fact]
        public void Delete_GET_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Delete(null);

            Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, ((StatusCodeResult)result).StatusCode);
        }

        [Fact]
        public void Delete_GET_ReturnsNotFound_WhenDepartmentDoesNotExist()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_GET_ReturnsView_WithDepartment()
        {
            var deptId = _context.Departments.First().DepartmentID;
            var result = _controller.Delete(deptId);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Department>(viewResult.Model);
            Assert.Equal(deptId, model.DepartmentID);
        }

        // --- DeleteConfirmed ---

        [Fact]
        public void DeleteConfirmed_RemovesDepartment_AndRedirectsToIndex()
        {
            var deptId = _context.Departments.First().DepartmentID;
            var initialCount = _context.Departments.Count();

            var result = _controller.DeleteConfirmed(deptId);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.Equal(initialCount - 1, _context.Departments.Count());
        }
    }
}

