using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests : IDisposable
    {
        private readonly SchoolContext _context;

        public SchoolContextTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
        }

        public void Dispose()
        {
            _context.Dispose();
        }

        [Fact]
        public void SchoolContext_CanAddAndRetrieveStudent()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Parse("2023-09-01")
            };

            _context.Students.Add(student);
            _context.SaveChanges();

            var retrieved = _context.Students.First();
            Assert.Equal("Test", retrieved.FirstMidName);
            Assert.Equal("Student", retrieved.LastName);
        }

        [Fact]
        public void SchoolContext_CanAddAndRetrieveInstructor()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2020-01-01")
            };

            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            Assert.Single(_context.Instructors);
        }

        [Fact]
        public void SchoolContext_CanAddAndRetrieveCourse()
        {
            var dept = new Department
            {
                Name = "Test",
                Budget = 100000,
                StartDate = DateTime.Parse("2020-01-01")
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course
            {
                CourseID = 1001,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            _context.Courses.Add(course);
            _context.SaveChanges();

            Assert.Single(_context.Courses);
        }

        [Fact]
        public void SchoolContext_CanAddAndRetrieveDepartment()
        {
            var dept = new Department
            {
                Name = "Test Department",
                Budget = 500000,
                StartDate = DateTime.Parse("2020-01-01")
            };

            _context.Departments.Add(dept);
            _context.SaveChanges();

            Assert.Single(_context.Departments);
        }

        [Fact]
        public void SchoolContext_CanAddAndRetrieveEnrollment()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.Now
            };
            _context.Students.Add(student);

            var dept = new Department
            {
                Name = "Test",
                Budget = 100000,
                StartDate = DateTime.Now
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course
            {
                CourseID = 2001,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var enrollment = new Enrollment
            {
                StudentID = student.ID,
                CourseID = course.CourseID,
                Grade = Grade.A
            };
            _context.Enrollments.Add(enrollment);
            _context.SaveChanges();

            Assert.Single(_context.Enrollments);
        }

        [Fact]
        public void SchoolContext_CanAddAndRetrieveNotification()
        {
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test notification",
                CreatedAt = DateTime.Now,
                CreatedBy = "System",
                IsRead = false
            };

            _context.Notifications.Add(notification);
            _context.SaveChanges();

            Assert.Single(_context.Notifications);
        }

        [Fact]
        public void SchoolContext_CourseAssignment_HasCompositeKey()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                LastName = "Instructor",
                HireDate = DateTime.Now
            };
            _context.Instructors.Add(instructor);

            var dept = new Department
            {
                Name = "Test",
                Budget = 100000,
                StartDate = DateTime.Now
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course
            {
                CourseID = 3001,
                Title = "Test",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var ca = new CourseAssignment
            {
                CourseID = course.CourseID,
                InstructorID = instructor.ID
            };
            _context.CourseAssignments.Add(ca);
            _context.SaveChanges();

            Assert.Single(_context.CourseAssignments);
        }

        [Fact]
        public void SchoolContext_OfficeAssignment_HasInstructorFK()
        {
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                LastName = "Instructor",
                HireDate = DateTime.Now
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var office = new OfficeAssignment
            {
                InstructorID = instructor.ID,
                Location = "Room 101"
            };
            _context.OfficeAssignments.Add(office);
            _context.SaveChanges();

            Assert.Single(_context.OfficeAssignments);
            Assert.Equal("Room 101", _context.OfficeAssignments.First().Location);
        }

        [Fact]
        public void SchoolContext_HasAllDbSets()
        {
            Assert.NotNull(_context.Courses);
            Assert.NotNull(_context.Enrollments);
            Assert.NotNull(_context.Departments);
            Assert.NotNull(_context.OfficeAssignments);
            Assert.NotNull(_context.CourseAssignments);
            Assert.NotNull(_context.People);
            Assert.NotNull(_context.Students);
            Assert.NotNull(_context.Instructors);
            Assert.NotNull(_context.Notifications);
        }
    }
}

