using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class DbInitializerTests
    {
        [Fact]
        public void Initialize_SeedsStudents()
        {
            var context = TestHelpers.CreateInMemoryContext();

            DbInitializer.Initialize(context);

            Assert.Equal(8, context.Students.Count());
            context.Dispose();
        }

        [Fact]
        public void Initialize_SeedsInstructors()
        {
            var context = TestHelpers.CreateInMemoryContext();

            DbInitializer.Initialize(context);

            Assert.Equal(5, context.Instructors.Count());
            context.Dispose();
        }

        [Fact]
        public void Initialize_SeedsDepartments()
        {
            var context = TestHelpers.CreateInMemoryContext();

            DbInitializer.Initialize(context);

            Assert.Equal(4, context.Departments.Count());
            context.Dispose();
        }

        [Fact]
        public void Initialize_SeedsCourses()
        {
            var context = TestHelpers.CreateInMemoryContext();

            DbInitializer.Initialize(context);

            Assert.Equal(7, context.Courses.Count());
            context.Dispose();
        }

        [Fact]
        public void Initialize_SeedsEnrollments()
        {
            var context = TestHelpers.CreateInMemoryContext();

            DbInitializer.Initialize(context);

            Assert.Equal(11, context.Enrollments.Count());
            context.Dispose();
        }

        [Fact]
        public void Initialize_SeedsOfficeAssignments()
        {
            var context = TestHelpers.CreateInMemoryContext();

            DbInitializer.Initialize(context);

            Assert.Equal(3, context.OfficeAssignments.Count());
            context.Dispose();
        }

        [Fact]
        public void Initialize_SeedsCourseAssignments()
        {
            var context = TestHelpers.CreateInMemoryContext();

            DbInitializer.Initialize(context);

            Assert.Equal(8, context.CourseAssignments.Count());
            context.Dispose();
        }

        [Fact]
        public void Initialize_DoesNotReseed_WhenStudentsExist()
        {
            var context = TestHelpers.CreateInMemoryContext();

            DbInitializer.Initialize(context);
            var firstCount = context.Students.Count();

            // Call again
            DbInitializer.Initialize(context);
            var secondCount = context.Students.Count();

            Assert.Equal(firstCount, secondCount);
            context.Dispose();
        }

        [Fact]
        public void Initialize_CreatesValidStudentData()
        {
            var context = TestHelpers.CreateInMemoryContext();

            DbInitializer.Initialize(context);

            var carson = context.Students.FirstOrDefault(s => s.LastName == "Alexander");
            Assert.NotNull(carson);
            Assert.Equal("Carson", carson.FirstMidName);
            context.Dispose();
        }

        [Fact]
        public void Initialize_CreatesDepartmentsWithInstructors()
        {
            var context = TestHelpers.CreateInMemoryContext();

            DbInitializer.Initialize(context);

            var english = context.Departments.FirstOrDefault(d => d.Name == "English");
            Assert.NotNull(english);
            Assert.NotNull(english.InstructorID);
            context.Dispose();
        }
    }
}

